/**
 * @description application brand logo with text, default size h-11,
 *  link to homepage
 */
const AppBrand = ({ height = 'h-11', className }: AppBrandProps) => {
  return (
    <MotionLink
      to='/'
      className={cn('flex items-center text-primary font-semibold', className)}
      whileHover={{ scale: 1.05 }}
      whileTap={{ scale: 0.9 }}
      viewTransition
    >
      <Brand className={cn(height, 'w-auto text-foreground')} />
    </MotionLink>
  );
};

export default AppBrand;
